import{c as a,Q as t,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-05-27","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-27","date":"2026-05-27T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-27-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-27-bens-bites.md","lastUpdated":1779927176000}`),n={name:"research/ai-news/2026-05/2026-05-27-bens-bites.md"};function s(i,e,l,h,p,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-05-27" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-27 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-27" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-27&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="is-saas-dead" tabindex="-1"><a href="https://www.bensbites.com/p/is-saas-dead" target="_blank" rel="noreferrer">Is SaaS dead?</a> <a class="header-anchor" href="#is-saas-dead" aria-label="Permalink to &quot;[Is SaaS dead?](https://www.bensbites.com/p/is-saas-dead)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-26</em></p><p>Hey folks,</p><p>It&#39;s a heatwave in the UK, and I can&#39;t think straight. Dan went on Lenny&#39;s podcast to talk about agents, automation and SaaSpocalypse, which is <a href="https://www.youtube.com/watch?v=4D3hDmGhFhA" target="_blank" rel="noreferrer">worth checking out</a>.</p><p>While I generally agree with it all, the one thing I can&#39;t shake is the bullish case for SaaS. I think SaaS is in trouble…</p><p>I don&#39;t think it&#39;s in trouble because you can build your own versions with a plan, patience and prompts.</p><p>With SaaS tools, you pay monthly for a set of features and stability. The problem is that the tool needs to keep growing. They add new features, change the interface, do all sorts of things you may not need (and often hate).</p><p>The tool is for the masses but you may have only wanted a sliver. The tools can outgrow you and why you bought it in the first place.</p><p>So if I only need a sliver, I&#39;ll go looking for pieces I can pull together myself. A document editor over here, an agent there, etc.</p><p>I think SaaS companies that can unbundle their building blocks and sell them as composable pieces for users (as well as the all-in bundle) could be a very interesting bet.</p><p>WorkOS do this well. Their tagline on Google results is literally &quot;<em>WorkOS</em> is a set of building blocks for quickly adding enterprise features to your app&quot;.</p><p>Stripe does this too.</p><p>In the age of customisable software and using tools with agents, I can&#39;t imagine paying for a tool that I can&#39;t change its feel or features.</p><p>It&#39;s why I think API/CLI/SDK-first companies are in a really interesting place.</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://www.sherlocq.ai/?utm_source=Newsletter&amp;utm_medium=Newsletter&amp;utm_campaign=Sherlocq+Launch&amp;utm_id=Bens+Bites" target="_blank" rel="noreferrer">Sherlocq</a></em></p><blockquote><p><a href="https://www.sherlocq.ai/?utm_source=Newsletter&amp;utm_medium=Newsletter&amp;utm_campaign=Sherlocq+Launch&amp;utm_id=Bens+Bites" target="_blank" rel="noreferrer">Sherlocq</a> is an AI-powered regulatory intelligence platform built for compliance, legal, and regulatory professionals. Research regulations, analyse documents, and run sanctions checks across 30+ jurisdictions and 320+ sanctions sources, <a href="https://www.sherlocq.ai/?utm_source=Newsletter&amp;utm_medium=Newsletter&amp;utm_campaign=Sherlocq+Launch&amp;utm_id=Bens+Bites" target="_blank" rel="noreferrer">cutting research time by up to 70%</a>.</p></blockquote><hr><h4 id="headlines" tabindex="-1">Headlines <a class="header-anchor" href="#headlines" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong><a href="https://x.com/OpenAIDevs/status/2057530207976989179" target="_blank" rel="noreferrer">Appshots in Codex</a></strong> attach the active Mac window to a Codex thread with a screenshot + available text, including context beyond what is visible. <a href="https://developers.openai.com/codex/prompting#goal-mode" target="_blank" rel="noreferrer">Goal mode</a> in Codex is now out of the experiment stage - it helps Codex execute multiple-step workflows with a single outcome in mind, with the ability to check back and compare its work with that goal. Plus, there are <a href="https://help.openai.com/en/articles/11391654-chatgpt-business-release-notes#:~:text=16%20hours%20ago-,May%2021%2C%202026,-Codex%20updates%3A%20richer" target="_blank" rel="noreferrer">other updates</a> like sharing plugins, using a Mac while it&#39;s locked and more.</p></li><li><p><strong><a href="https://blog.modelcontextprotocol.io/posts/2026-07-28-release-candidate/" target="_blank" rel="noreferrer">MCP is getting a major upgrade</a></strong> (finalizes on July 28). It should be much easier to run MCP servers reliably at scale. The update also adds built-in support for app-like interfaces, long-running tasks, stronger login/security rules, better tool definitions, and a clearer process for changing the protocol over time.</p></li><li><p><strong><a href="https://www.perplexity.ai/hub/blog/perplexity-is-open-sourcing-bumblebee" target="_blank" rel="noreferrer">Perplexity open-sourced Bumblebee</a></strong> - A safety scanner for developer machines. It checks for risky packages, browser/editor extensions, and AI agent configs, without running any of the tools it is inspecting. So it can flag supply-chain risks without accidentally triggering the same risky code.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed" tabindex="-1">My feed <a class="header-anchor" href="#my-feed" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p><a href="https://github.com/nkzw-tech/cloudsail" target="_blank" rel="noreferrer">Cloudsail</a> - fresh Cloudflare Sandboxes for coding agents, with shell, Codex and GitHub access.</p></li><li><p><a href="https://workos.com/blog/agent-registration-with-auth-md" target="_blank" rel="noreferrer">WorkOS released auth.md</a>, an open protocol for agents to register for web services on behalf of users</p></li><li><p><a href="https://lucumr.pocoo.org/2026/5/24/pi-oss/" target="_blank" rel="noreferrer">Building Pi With Pi</a> - using agents for issue research, PR wrap-ups, context tracking and parallel work.</p></li><li><p>An <a href="https://github.com/zeke/agents.md" target="_blank" rel="noreferrer">AGENTS.md file</a> with a year of small agent-behaviour improvements.</p></li><li><p><a href="https://release.bar/" target="_blank" rel="noreferrer">release.bar</a> - trending active GitHub repos, with a dashboard for each repo/builder. (<a href="https://release.bar/steipete" target="_blank" rel="noreferrer">see example</a>). GitHub should probably have shipped this already.</p></li><li><p><a href="https://hyperjs.ai/" target="_blank" rel="noreferrer">Hyper</a> - Bun API framework you copy into your codebase instead of installing as a dependency.</p></li><li><p><a href="https://x.com/swyx/status/2057876022553690327" target="_blank" rel="noreferrer">Kakuna</a> - Checklist-driven codebase hardening, and a <a href="https://x.com/swyx/status/2057559570177007912" target="_blank" rel="noreferrer">production-ready repo skill</a> that turns a fragile vibe-coded app into something maintainable and agent-friendly.</p></li><li><p>Cursor&#39;s internal <a href="https://x.com/ericzakariasson/status/2057521364622553442" target="_blank" rel="noreferrer">/thermo-nuclear-code-quality-review</a> skill deletes complexity, blocks huge files and rejects PRs that work but make the codebase messier.</p></li><li><p><a href="https://simpleplayer.grizz.fyi/" target="_blank" rel="noreferrer">Simpleplayer</a> - clean default video player with custom overlay controls.</p></li><li><p><a href="https://www.youtube.com/watch?v=IDqdVZwAwjw" target="_blank" rel="noreferrer">Running a startup solo with AI agents</a> - OpenClaw as Chief of Staff, Codex/Devin as engineering and giving agents real email, calendar and GitHub access.</p></li><li><p><a href="https://x.com/IShmool/status/2057872918348976191" target="_blank" rel="noreferrer">zero2claude</a> - free course from zero terminal experience to shipping with Claude Code.</p></li><li><p>Find repeated workflows across recent sessions/memories, then create only the <a href="https://x.com/reach_vb/status/2058538305872949490" target="_blank" rel="noreferrer">smallest useful skill</a>, subagent or automation.</p></li><li><p><a href="https://x.com/mattyp/status/2057560837653688396" target="_blank" rel="noreferrer">Shades</a> - Chrome extension that hides sensitive inputs while screen recording or sharing.</p></li><li><p><a href="https://plannotator.ai/" target="_blank" rel="noreferrer">Plannotator</a> - annotate agent plans before they run and review the output in full diffs.</p></li><li><p><a href="https://x.com/ryanbrewer/status/2057524413785063468" target="_blank" rel="noreferrer">ChatGPT for PowerPoint</a> - create slides, ask questions across a deck, and make updates inside PowerPoint.</p></li></ul><hr><h4 id="afters" tabindex="-1">Afters <a class="header-anchor" href="#afters" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="google-s-take-on-openclaw" tabindex="-1"><a href="https://www.bensbites.com/p/googles-take-on-openclaw" target="_blank" rel="noreferrer">Google&#39;s take on openclaw</a> <a class="header-anchor" href="#google-s-take-on-openclaw" aria-label="Permalink to &quot;[Google&#39;s take on openclaw](https://www.bensbites.com/p/googles-take-on-openclaw)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-21</em></p><p>Hey folks,</p><p>My first fund is now at 5x! I had a very notable firm not invest in my latest fund as they were assessing if I was a 5x fund returner… seems like I am. Fund 2 is also at ~3x with 55% IRR. Fund 3 I&#39;m starting to fundraise for again, looking for operators, $100k minimum. Deployed 4 cheques so far. I invest in developer tools and infrastructure - essentially anything for an agent-first world. If you or anyone you know would be interested, please let me know.</p><p>Google&#39;s I/O event on Tuesday was overshadowed by <a href="https://x.com/karpathy/status/2056753169888334312" target="_blank" rel="noreferrer">Andrej Karpathy joining Antrhopic&#39;s pre-training team</a> under Nick Joseph to build and lead a new group focused on using Claude to accelerate pre-training research. Using Claude to help pre-train Claude models.</p><p>And now they have the compute… SpaceX&#39;s IPO filing discloses Anthropic will pay $1.25 billion monthly for compute.</p><p>Just as Anthropic project $10.9 billion June quarter revenue and its first operating profit. Which could well lead them to a valuation higher than OpenAI. Who have been reported are potentially filing for an IPO imminently (some sources say as early as tomorrow) - but nothing official or confirmed.</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Attio, the AI CRM</a></em></p><blockquote><p>GTM Atlas is the map for modern go-to-market. Written by top operators, Atlas is a free resource covering the full customer journey, with systems thinking that scales with you. Curated by Attio. Mapped by operators. <a href="http://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Read now</a></p></blockquote><hr><h4 id="headlines-1" tabindex="-1">Headlines <a class="header-anchor" href="#headlines-1" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p>Google I/O wasn&#39;t all that interesting.</p><ul><li><p>They have a new model family aiming for any input/any output. <strong><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-omni/" target="_blank" rel="noreferrer">Gemini Omni Flash</a></strong> - the first model in that family generates and edits videos. The technical difference between Omni and Veo is similar to that between Imagen and Nano Banana.</p></li><li><p>For general model upgrades, they only released <strong><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-5/" target="_blank" rel="noreferrer">Gemini 3.5 Flash</a>,</strong> which, on paper, is better than 3.1 Pro. This model is fast and intelligent, but not cheap anymore. It also has the knowledge cutoff of Jan 2025, so it does not know about vibe coding and beyond. 3.5 Pro is coming next month, but I don&#39;t have high hopes.</p></li><li><p><strong><a href="https://blog.google/innovation-and-ai/technology/developers-tools/google-io-2026-developer-highlights/" target="_blank" rel="noreferrer">Antigravity</a></strong> is now a clone of Codex, Conductor and every other AI coding agent app. It&#39;s usable -- but I couldn&#39;t find a way to bypass permission quickly. They have also made installing the IDE optional.</p></li><li><p>Their answer to OpenClaw is called <strong><a href="https://blog.google/innovation-and-ai/products/gemini-app/next-evolution-gemini-app/" target="_blank" rel="noreferrer">Gemini Spark</a></strong> , a 24/7 personal agent that works across Workspace, but it&#39;s &quot;coming soon&quot;, so no idea how well it works.</p></li></ul></li><li><p>OpenAI says one of its models <strong><a href="https://openai.com/index/model-disproves-discrete-geometry-conjecture/" target="_blank" rel="noreferrer">solved a famous math problem</a>,</strong> and external mathematicians checked the proof. They also added a <strong><a href="https://openai.com/index/advancing-content-provenance/" target="_blank" rel="noreferrer">public image verifier</a></strong> for images made with ChatGPT, the API and Codex. It checks C2PA metadata and also SynthID (from Google). <a href="https://openai.com/verify/" target="_blank" rel="noreferrer">Try it here</a>.</p></li><li><p><strong><a href="https://www.figma.com/blog/the-figma-agent-is-here/" target="_blank" rel="noreferrer">Figma has a design agent inside the canvas</a></strong>. It can start from a design layer, generate multiple directions in parallel, make bulk edits, use your design system, and work in the same file as your team.</p></li><li><p>Now any product developer can ship globally: <strong>Neimo MCP</strong> turns Claude, OpenAI&#39;s Codex, and Manus into regulatory experts across 200+ jurisdictions. Built by <a href="https://gamesbeat.com/k-id-launches-ai-powered-compliance-tool-aimed-at-speeding-global-game-launches-exclusive/" target="_blank" rel="noreferrer">the team</a> behind compliance for some of the world&#39;s largest games and platforms. <a href="https://k-id.com/neimo-mcp?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=44143235-Neimo-MCP-Launch&amp;utm_content=text_cta" target="_blank" rel="noreferrer">Try Neimo free 👉</a>*</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed-1" tabindex="-1">My feed <a class="header-anchor" href="#my-feed-1" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p><a href="https://handinger.com" target="_blank" rel="noreferrer">Handinger</a>: Build AI agents in plain English, connect them to your tools, and kill the boring admin work nobody wants.*</p></li><li><p><a href="https://x.com/FactoryAI/status/2057178459911467162" target="_blank" rel="noreferrer">Factory&#39;s Deferred Context Engine</a> - Droid now loads tools more selectively to cut context size by 40%.</p></li><li><p><a href="https://x.com/jxnlco/status/2057153744630890620" target="_blank" rel="noreferrer">Getting the most out of Codex</a>.</p></li><li><p><a href="https://x.com/nbaschez/status/2057139892883464243" target="_blank" rel="noreferrer">Roughdraft</a> - local open-source interface for commenting and suggested changes on markdown docs/plans.</p></li><li><p><a href="https://x.com/pierrecomputer/status/2057174934674124941" target="_blank" rel="noreferrer">DiffsHub</a> - replace <em>github</em> with <em>diffshub</em> in a public GitHub diff URL to virtualise and inspect huge diffs quickly.</p></li><li><p><a href="https://x.com/astuyve/status/2056772052636319955" target="_blank" rel="noreferrer">Lapdog</a> from Datadog - local tracing for reasoning and tool calls in Codex, Claude Code and Pi.</p></li><li><p><a href="https://x.com/meetgranola/status/2057100483219857868" target="_blank" rel="noreferrer">Granola Briefs</a> - searches your email, web and previous meeting notes before a meeting, then gives you three bullets.</p></li><li><p><a href="https://buildwithtaste.com/product/mcp" target="_blank" rel="noreferrer">Taste MCP</a> - what if your design preferences could follow you into Codex, Cursor, Claude Code?</p></li><li><p><a href="https://openai.com/business/guaranteed-capacity/" target="_blank" rel="noreferrer">OpenAI Guaranteed Capacity</a> - companies can pre-book OpenAI compute for 1-3 years, so important products and agents don&#39;t get throttled when demand spikes.</p></li><li><p><a href="https://x.com/p0/status/2056752047031279726" target="_blank" rel="noreferrer">Parallel Web Systems Index</a> - lets publishers see which agents are reading their content and get paid. First partners include The Atlantic, Fortune, Every and Packy.</p></li><li><p><a href="https://x.com/yoheinakajima/status/2057099245430222926" target="_blank" rel="noreferrer">Active Graph</a> - open-source framework for long-running agents to remember what happened, react to new events, and compare different agent runs.</p></li><li><p>Making <a href="https://x.com/ClaudeDevs/status/2056835339193561170" target="_blank" rel="noreferrer">computer use</a> reliable in production.</p></li><li><p>A poisoned third-party VS Code extension compromised a GitHub employee&#39;s device, and <a href="https://github.blog/security/investigating-unauthorized-access-to-githubs-internal-repositories/" target="_blank" rel="noreferrer">~3,800 internal GitHub repos were exfiltrated</a>.</p></li><li><p><a href="https://cohere.com/blog/command-a-plus" target="_blank" rel="noreferrer">Cohere released Command A+</a> - an open-source enterprise model. supports text/image/tool use and runs on two H100s/one B200 with quantisation.</p></li></ul><hr><h4 id="afters-1" tabindex="-1">Afters <a class="header-anchor" href="#afters-1" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible-1" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible-1" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter-1" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter-1" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com-1" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com-1" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr>',62)])])}const d=a(n,[["render",s]]);export{m as __pageData,d as default};
